import React, { useState, useEffect, useRef } from 'react';
import { Outlet, useNavigate, useLocation, NavLink } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import axios from 'axios';

// Sophisticated SVG Icons
const Icons = {
  Bus: () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
      <path d="M19 17h2a2 2 0 0 0 2-2V7a2 2 0 0 0-2-2H3a2 2 0 0 0-2 2v8a2 2 0 0 0 2 2h2"/>
      <circle cx="7" cy="17" r="2"/><circle cx="17" cy="17" r="2"/>
      <path d="M5 17h10M13 5v8M1 9h22M5 5v4"/>
    </svg>
  ),
  Dashboard: () => (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <rect x="3" y="3" width="7" height="7" rx="1"/><rect x="14" y="3" width="7" height="7" rx="1"/>
      <rect x="14" y="14" width="7" height="7" rx="1"/><rect x="3" y="14" width="7" height="7" rx="1"/>
    </svg>
  ),
  Students: () => (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/>
      <path d="M23 21v-2a4 4 0 0 0-3-3.87M16 3.13a4 4 0 0 1 0 7.75"/>
    </svg>
  ),
  Route: () => (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <circle cx="12" cy="12" r="10"/><path d="M12 2a15.3 15.3 0 0 1 4 10 15.3 15.3 0 0 1-4 10 15.3 15.3 0 0 1-4-10 15.3 15.3 0 0 1 4-10z"/>
      <path d="M2 12h20"/>
    </svg>
  ),
  Fees: () => (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <line x1="12" y1="1" x2="12" y2="23"/><path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/>
    </svg>
  ),
  Calendar: () => (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/>
    </svg>
  ),
  Alert: () => (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/>
    </svg>
  ),
  Profile: () => (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/>
    </svg>
  ),
  Bell: () => (
    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"/><path d="M13.73 21a2 2 0 0 1-3.46 0"/>
    </svg>
  ),
  Logout: () => (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/><polyline points="16 17 21 12 16 7"/><line x1="21" y1="12" x2="9" y2="12"/>
    </svg>
  )
};

const adminNav = [
  { section: 'Dashboard', items: [
    { to: '/admin/dashboard', label: 'Overview', icon: <Icons.Dashboard /> },
  ]},
  { section: 'Management', items: [
    { to: '/admin/students', label: 'Students', icon: <Icons.Students /> },
    { to: '/admin/routes', label: 'Bus Routes', icon: <Icons.Route /> },
    { to: '/admin/fees', label: 'Fee Records', icon: <Icons.Fees /> },
  ]},
  { section: 'Scheduling', items: [
    { to: '/admin/schedules', label: 'Schedules', icon: <Icons.Calendar /> },
    { to: '/admin/upcoming', label: 'Upcoming Dues', icon: <Icons.Calendar /> },
    { to: '/admin/overdue', label: 'Overdue Dues', icon: <Icons.Alert /> },
  ]},
  { section: 'System', items: [
    { to: '/admin/profile', label: 'Admin Profile', icon: <Icons.Profile /> },
  ]},
];

const studentNav = [
  { section: 'Portal', items: [
    { to: '/student/dashboard', label: 'Dashboard', icon: <Icons.Dashboard /> },
    { to: '/student/fees', label: 'Fees & Receipts', icon: <Icons.Fees /> },
    { to: '/student/schedule', label: 'Fee Schedule', icon: <Icons.Calendar /> },
    { to: '/student/notifications', label: 'Notifications', icon: <Icons.Bell /> },
  ]},
  { section: 'Account', items: [
    { to: '/student/profile', label: 'My Profile', icon: <Icons.Profile /> },
  ]},
];

const pageTitles = {
  '/admin/dashboard': { title: 'Analytics Dashboard', sub: 'Performance overview of bus fees collection' },
  '/admin/students': { title: 'Student Management', sub: 'Maintain records of transport-registered students' },
  '/admin/routes': { title: 'Transit Routes', sub: 'Define and configure institute bus paths' },
  '/admin/fees': { title: 'Fee Tracking', sub: 'Real-time record of all fee transactions' },
  '/admin/schedules': { title: 'Payment Windows', sub: 'Control fee generation and deadlines' },
  '/admin/upcoming': { title: 'Revenue Pipeline', sub: 'Fees maturing in the next 30 days' },
  '/admin/overdue': { title: 'Collection Recovery', sub: 'Monitor and manage past-due accounts' },
  '/admin/profile': { title: 'Account Configuration', sub: 'Manage your administrative identity' },
  '/student/dashboard': { title: 'Student Portal', sub: 'Personalized fee and route summary' },
  '/student/fees': { title: 'Financial History', sub: 'Payments, pending dues, and digital receipts' },
  '/student/schedule': { title: 'College Schedule', sub: 'Transportation payment policy and timelines' },
  '/student/profile': { title: 'Profile Verification', sub: 'Personal, academic, and transit details' },
  '/student/notifications': { title: 'Communication Hub', sub: 'Important alerts and announcements' },
};

export default function Layout() {
  const { user, logout, isAdmin } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [notifications, setNotifications] = useState([]);
  const [showNotif, setShowNotif] = useState(false);
  const notifRef = useRef(null);

  useEffect(() => {
    axios.get('/notifications').then(r => setNotifications(r.data)).catch(() => {});
  }, [location.pathname]);

  useEffect(() => {
    const handler = (e) => {
      if (notifRef.current && !notifRef.current.contains(e.target)) setShowNotif(false);
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  const unread = notifications.filter(n => !n.isRead).length;
  const page = pageTitles[location.pathname] || { title: 'KEC Bus Portal', sub: 'Institutional Transport Management' };
  const navGroups = isAdmin ? adminNav : studentNav;

  const handleLogout = () => { logout(); navigate('/login'); };

  const markAllRead = async () => {
    try {
      await axios.put('/notifications/read-all');
      setNotifications(n => n.map(x => ({ ...x, isRead: true })));
    } catch (e) {}
  };

  const timeAgo = (date) => {
    const diff = Date.now() - new Date(date);
    const m = Math.floor(diff / 60000);
    if (m < 1) return 'just now';
    if (m < 60) return `${m}m ago`;
    const h = Math.floor(m / 60);
    if (h < 24) return `${h}h ago`;
    return `${Math.floor(h / 24)}d ago`;
  };

  return (
    <div className="layout">
      {sidebarOpen && <div className="sidebar-overlay" onClick={() => setSidebarOpen(false)} />}

      <aside className={`sidebar ${sidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-logo">
          <div className="brand-mark">
            <Icons.Bus />
          </div>
          <div>
            <div className="brand-name">KEC Transport</div>
            <div className="brand-sub">{isAdmin ? 'Admin Console' : 'Student Hub'}</div>
          </div>
        </div>

        <nav className="sidebar-nav">
          {navGroups.map(group => (
            <div key={group.section} className="nav-group">
              <div className="nav-section-label">{group.section}</div>
              {group.items.map(item => (
                <NavLink
                  key={item.to}
                  to={item.to}
                  className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}
                  onClick={() => setSidebarOpen(false)}
                >
                  {item.icon}
                  <span>{item.label}</span>
                  {item.to === '/student/notifications' && unread > 0 && (
                    <span style={{
                      marginLeft: 'auto', background: '#dc2626', color: 'white',
                      fontSize: 10, fontWeight: 800, padding: '2px 6px', borderRadius: 10
                    }}>{unread}</span>
                  )}
                </NavLink>
              ))}
            </div>
          ))}
        </nav>

        <div className="sidebar-footer">
          <div className="user-card" onClick={() => navigate(isAdmin ? '/admin/profile' : '/student/profile')} style={{ cursor: 'pointer' }}>
            <div className="user-avatar">{user?.name?.charAt(0).toUpperCase()}</div>
            <div className="user-info">
              <div className="user-name">{user?.name}</div>
              <div className="user-role">{user?.role}</div>
            </div>
          </div>
          <button className="logout-btn" onClick={handleLogout}>
            <Icons.Logout /> Sign Out
          </button>
        </div>
      </aside>

      <main className="main-content">
        <header className="topbar">
          <div className="topbar-left">
            <button className="menu-toggle" onClick={() => setSidebarOpen(true)} aria-label="Open menu" style={{
              background: 'none', border: 'none', fontSize: 24, cursor: 'pointer', padding: 8, marginRight: 12
            }}>☰</button>
            <div>
              <h2>{page.title}</h2>
              <p>{page.sub}</p>
            </div>
          </div>

          <div className="topbar-right">
            <div className="portal-name-topbar">KEC Bus Fees Portal</div>

            <div style={{ position: 'relative' }} ref={notifRef}>
              <button className="notif-btn" onClick={() => setShowNotif(!showNotif)} title="Notifications" aria-label="Notifications" style={{
                background: 'var(--surface2)', border: 'none', width: 40, height: 40, borderRadius: 10, 
                display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', position: 'relative', transition: '0.2s'
              }}>
                <Icons.Bell />
                {unread > 0 && <span className="notif-dot" style={{
                  position: 'absolute', top: 10, right: 10, width: 8, height: 8, background: '#ef4444', borderRadius: '50%', border: '2px solid var(--surface)'
                }} />}
              </button>

              {showNotif && (
                <div className="notif-panel" style={{
                  position: 'absolute', top: '120%', right: 0, width: 340, background: 'white',
                  borderRadius: 16, boxShadow: 'var(--shadow-xl)', border: '1px solid var(--border)', overflow: 'hidden', animation: 'fadeIn 0.2s ease-out'
                }}>
                  <div className="card-header" style={{ borderBottom: '1px solid var(--border-light)', padding: '16px 20px' }}>
                    <span style={{ fontWeight: 800, fontSize: 14 }}>Notifications</span>
                    {unread > 0 && <button className="btn btn-sm" style={{ background: 'none', color: 'var(--primary)', fontWeight: 700 }} onClick={markAllRead}>Clear all</button>}
                  </div>
                  <div className="notif-list" style={{ maxHeight: 400, overflowY: 'auto' }}>
                    {notifications.length === 0 ? (
                      <div className="notif-empty" style={{ padding: 40, textAlign: 'center', color: 'var(--text-light)', fontSize: 13 }}>
                        <div style={{ fontSize: 32, marginBottom: 16 }}>🔔</div>
                        Everything up to date!
                      </div>
                    ) : notifications.slice(0, 5).map(n => (
                      <div key={n.id} className="notif-item" style={{
                        padding: '16px 20px', borderBottom: '1px solid var(--border-light)', 
                        background: !n.isRead ? 'rgba(var(--primary-rgb), 0.03)' : 'transparent', cursor: 'pointer'
                      }} onClick={() => {
                        axios.put(`/notifications/${n.id}/read`);
                        setNotifications(prev => prev.map(x => x.id === n.id ? { ...x, isRead: true } : x));
                      }}>
                        <div style={{ fontWeight: 700, fontSize: 13, marginBottom: 4 }}>{n.title}</div>
                        <div style={{ fontSize: 13, color: 'var(--text-muted)', marginBottom: 8, lineHeight: 1.4 }}>{n.message}</div>
                        <div style={{ fontSize: 11, color: 'var(--text-light)' }}>{timeAgo(n.createdAt)}</div>
                      </div>
                    ))}
                  </div>
                  <div className="card-footer" style={{ padding: 12, textAlign: 'center', background: 'var(--surface2)' }}>
                    <button className="btn btn-sm btn-outline" style={{ width: '100%', justifyContent: 'center' }} onClick={() => { setShowNotif(false); navigate(isAdmin ? '/admin/dashboard' : '/student/notifications'); }}>
                      View All Activity
                    </button>
                  </div>
                </div>
              )}
            </div>

            <div className="topbar-date">
              {new Date().toLocaleDateString('en-IN', { weekday: 'short', day: 'numeric', month: 'short' })}
            </div>
          </div>
        </header>

        <div className="page-content">
          <Outlet />
        </div>
      </main>
    </div>
  );
}
